      "content": "const { sendError } = require('../../lib/errors');
const { randomUUID } = require('node:crypto');

const projects = {};

const addTask = (projectId, description) => {
  if (!projects[projectId]) {
    return null;
  }

  const project = projects[projectId];
  const task = { id: randomUUID(), description, status: 'todo' };
  project.tasks.push(task);
  return task;
};

const getTasks = (projectId, status) => {
  const project = projects[projectId];
  if (!project) {
    return null;
  }

  if (status) {
    return project.tasks.filter(task => task.status === status);
  }

  return project.tasks;
};

const updateTaskStatus = (projectId, taskId, newStatus) => {
  if (!projects[projectId]) {
    return null;
  }

  const project = projects[projectId];
  const task = project.tasks.find(task => task.id === taskId);

  if (!task) {
    return null;
  }

  if (newStatus !== 'todo' && newStatus !== 'done') {
    return null;
  }

  task.status = newStatus;
  return task;
};

module.exports = {
  addTask,
  getTasks,
  updateTaskStatus,
};
